const load=async(u="greg")=>{
  if(!supabase){try{const d=localStorage.getItem("coinspire_"+u);return d?JSON.parse(d):null}catch{return null}}
  try{const{data,error}=await supabase.from("user_data").select("data").eq("user_id",u).single();if(error)return null;return data?.data||null}catch{return null}
};

const sv=async(d,u="greg")=>{
  if(!supabase){
    try{
      if(d==null)localStorage.removeItem("coinspire_"+u);
      else localStorage.setItem("coinspire_"+u,JSON.stringify(d));
    }catch(e){console.error(e)}
    return;
  }
  try{
    if(d==null){await supabase.from("user_data").delete().eq("user_id",u);return}
    await supabase.from("user_data").upsert({user_id:u,data:d},{onConflict:"user_id"});
  }catch(e){console.error(e)}
};

